var scene = new THREE.Scene();
var camera = new THREE.PerspectiveCamera(90, window.innerWidth/window.innerHeight, 0.1, 1000);

var canvas = document.getElementById("myCanvas");
canvas.width = 600; 
canvas.height = window.innerHeight;

var renderer = new THREE.WebGLRenderer({
  canvas: canvas,
  antialias: true,
  alpha: true
});

renderer.setPixelRatio(window.devicePixelRatio);
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.autoClear = false;
renderer.clear();

renderer.setSize(600, 600);
renderer.setClearColor(0xffffff, 0);

camera.aspect = 3000 / 3000;
camera.updateProjectionMatrix();

var radius = 2;
var height = 0.2;
var segments = 666;

var textureLoader = new THREE.TextureLoader();
var texture = textureLoader.load( 'data:image/jpeg;base64,' );
texture.magFilter = THREE.LinearFilter;
texture.minFilter = THREE.LinearFilter;

var topMaterial = new THREE.MeshPhongMaterial({
  map: texture,
  flatShading: true,
  side: THREE.DoubleSide,
  shininess: 100, 
  reflectivity: 0.1
});

topMaterial.magFilter = THREE.LinearFilter;
topMaterial.minFilter = THREE.LinearFilter;

var cylinderGeometry = new THREE.CylinderGeometry(radius, radius, height, segments);
var faceMaterialIndex = 2;
cylinderGeometry.faces.forEach(function(face) {
  if (face.materialIndex === faceMaterialIndex) {
    face.materialIndex = 1;
  }
});

var material = new THREE.MeshFaceMaterial([
  new THREE.MeshPhongMaterial({
    color: 0x1E88E5,
    flatShading: true,
    side: THREE.DoubleSide
  }),
  topMaterial
]);

var cylinder = new THREE.Mesh(cylinderGeometry, material);

cylinder.rotation.x = Math.PI/2;

cylinder.receiveShadow = true;

var ambientLight = new THREE.AmbientLight(0xFFFFFF, 0.8);
scene.add(ambientLight);

var directionalLight = new THREE.DirectionalLight(0xffffff, 0.5);
directionalLight.position.set(0, 5, 5);
directionalLight.castShadow = true;
scene.add(directionalLight);

scene.add(cylinder);

camera.position.z = 3.5;
camera.position.x = 0; 
camera.position.y = 0;
camera.lookAt(0, 0, 0);

function animate() {
  requestAnimationFrame(animate);
  // cylinder.rotation.x += -0.01;
  cylinder.rotation.z += 0.01;
  renderer.render(scene, camera);
}
animate();